import { pseudoPermutation } from './feistel.min.js';
// 게임 변수 초기화
var ROWS = 5;
var COLS = 10;
var TARGET_SUM = 10;
var TIME_LIMIT = 100;
var CELL_SIZE = 32; // 셀 크기(픽셀)
var GRID_GAP = 4; // 그리드 셀 간격(픽셀)
var GRID_PADDING = 4; // 그리드 패딩(픽셀)
var HINT_DELAY = 0; // 힌트가 표시되기까지의 시간(ms)
