var selectionEndCell = null; // 선택 종료 셀 추가
var emptyCellCount = 0;
var currentSelectionSize = null;
var lastClearTime = 0; // 마지막으로 셀을 클리어한 시간
var hintTimer = null; // 힌트 타이머
var currentHint = null; // 현재 표시 중인 힌트
var isHintVisible = false; // 힌트 표시 상태
