var secondLastVisibleHint = null; // 두 번째로 최근에 표시된 힌트 저장
// 추가: 힌트 캐싱을 위한 변수들
var cachedHints = null; // 캐시된 힌트 목록
var gameStateChanged = true; // 게임 상태 변경 여부
var lastShownHintIndex = -1; // 마지막으로 표시된 힌트의 인덱스
